#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char mainLight[30];
    char blinking[30];
    for (int i = 0; i < T; ++i) {
        if (!fgets(mainLight, sizeof(mainLight), stdin)) break;
        if (!fgets(blinking, sizeof(blinking), stdin)) break;
        mainLight[strcspn(mainLight, "\n")] = '\0';
        blinking[strcspn(blinking, "\n")] = '\0';
        if (strcmp(mainLight, "red") == 0 || strcmp(blinking, "flashing red") == 0) {
            printf("Stop\n");
        } else if (strcmp(mainLight, "yellow") == 0 || strcmp(blinking, "blinking yellow") == 0) {
            printf("Slow Down\n");
        } else if (strcmp(mainLight, "green") == 0 || strcmp(blinking, "blinking green") == 0) {
            printf("Go\n");
        } else {
            printf("Invalid input\n");
        }
    }
    return 0;
}

