import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String mainLight = br.readLine();
            String blinking = br.readLine();
            String out;
            if ("red".equals(mainLight) || "flashing red".equals(blinking)) {
                out = "Stop";
            } else if ("yellow".equals(mainLight) || "blinking yellow".equals(blinking)) {
                out = "Slow Down";
            } else if ("green".equals(mainLight) || "blinking green".equals(blinking)) {
                out = "Go";
            } else {
                out = "Invalid input";
            }
            sb.append(out);
            if (i < T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

