#!/usr/bin/env python3
import sys
lines = sys.stdin.read().splitlines()
if not lines:
    sys.exit()
T = int(lines[0].strip())
idx = 1
out = []
for _ in range(T):
    if idx + 1 >= len(lines):
        break
    main_light = lines[idx].strip()
    blinking = lines[idx+1].strip()
    idx += 2
    if main_light == "red" or blinking == "flashing red":
        out.append("Stop")
    elif main_light == "yellow" or blinking == "blinking yellow":
        out.append("Slow Down")
    elif main_light == "green" or blinking == "blinking green":
        out.append("Go")
    else:
        out.append("Invalid input")
print("\n".join(out))

